#!/usr/bin/env bash
case $- in *i*) clear; . /etc/katsu/config.env 2>/dev/null || true; echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━"; echo "      SYSTEM INFORMATION"; echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━"; printf " System OS : %s\n" "$(grep PRETTY_NAME /etc/os-release | cut -d= -f2 | tr -d '\"')"; printf " Core CPU  : %s\n" "$(nproc)"; printf " Server RAM: %s / %s MB\n" "$(free -m | awk '/Mem:/ {print $3}')" "$(free -m | awk '/Mem:/ {print $2}')"; printf " Uptime    : %s\n" "$(uptime -p | sed 's/up //')"; printf " Domain    : %s\n" "${DOMAIN:-unknown}"; printf " IP VPS    : %s\n" "$(curl -4fsSL https://ipv4.icanhazip.com 2>/dev/null || echo unknown)"; echo "━━━━━━━━━━━━━━━━━━━━━━━━━━━━"; echo "Ketik: menu"; echo;; esac
